// File: select\script.js
class CustomSelect {
    constructor(element) {
        if (!element) {
            document.querySelectorAll('.select').forEach(el => new CustomSelect(el));
            return;
        }

        this.select = element;
        this.label = this.select.querySelector('.select-label');
        this.display = this.select.querySelector('.selected-option');
        this.list = this.select.querySelector('.select-list');
        this.items = this.select.querySelectorAll('.select-option:not(.disable)');

        this.bindEvents();
    }

    bindEvents() {
        this.select.addEventListener('click', (e) => this.toggleList(e));

        this.items.forEach(item => {
            item.addEventListener('click', () => this.selectItem(item));
        });

        document.addEventListener('click', (e) => {
            if (!this.select.contains(e.target)) {
                this.select.classList.remove('active');
            }
        });
    }

    toggleList(e) {
        if (e.target.tagName.toLowerCase() === 'li' && !e.target.classList.contains('disable')) return;

        const rect = this.select.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        const spaceAbove = rect.top;

        if (spaceBelow < 250 && spaceAbove > spaceBelow) {
            this.select.classList.remove('open-down');
            this.select.classList.add('open-up');
        } else {
            this.select.classList.remove('open-up');
            this.select.classList.add('open-down');
        }

        this.select.classList.toggle('active');
    }

    selectItem(item) {
        this.items.forEach(i => i.classList.remove('selected-option'));
        item.classList.add('selected-option');
        
        if (!this.display) {
            this.display = document.createElement('div');
            this.display.classList.add('selected-option');
            this.select.appendChild(this.display);
        }
        
        this.display.textContent = item.textContent;
        this.select.classList.remove('active');
        this.select.classList.add('has-value');
    }
}
new CustomSelect();

// File: tab\script.js
class Tabs {
    constructor() {
        this.init();
    }

    init() {
        document.querySelectorAll('.tab').forEach(container => {
            const tabList = container.querySelector('.tab-list');
            const labels = container.querySelectorAll('.tab-label');
            const contents = container.querySelectorAll('.tab-content');
            const position = container.getAttribute('data-tab-list-position');
            let slider = null;

            if (position === 'bottom' || position === 'top') {
                container.style.flexDirection = 'column';
            } else if (position === 'left' || position === 'right') {
                container.style.flexDirection = 'row';
                tabList.style.flexDirection = 'column';
            }

            if (container.classList.contains('tab-list-slider')) {
                slider = tabList.querySelector('.tab-slider');
                if (!slider) {
                    slider = document.createElement('div');
                    slider.classList.add('tab-slider');
                    tabList.appendChild(slider);
                }
            }

            const moveSlider = (activeLabel) => {
                if (!slider) return;

                const rect = activeLabel.getBoundingClientRect();
                const parentRect = activeLabel.parentElement.getBoundingClientRect();

                if (position === 'left' || position === 'right') {
                    const height = rect.height;
                    const top = rect.top - parentRect.top;
                    slider.style.height = `${height}px`;
                    slider.style.transform = `translateY(${top}px)`;
                    slider.style.top = '0%';
                } else {
                    const width = rect.width;
                    const left = rect.left - parentRect.left;
                    slider.style.width = `${width}px`;
                    slider.style.transform = `translateX(${left}px)`;
                    slider.style.left = '0%';
                }
            };

            const setActiveTab = (index) => {
                labels.forEach(l => l.classList.remove('active'));
                contents.forEach(c => c.classList.remove('active'));

                labels[index].classList.add('active');
                contents[index].classList.add('active');
                moveSlider(labels[index]);
            };

            labels.forEach((label, idx) => {
                label.addEventListener('click', () => setActiveTab(idx));
            });

            const activeLabel = container.querySelector('.tab-label.active');
            if (activeLabel) moveSlider(activeLabel);
        });
    }
}

new Tabs();

// File: table\script.js
class TablePaginator {
    constructor() {
        this.tables = document.querySelectorAll('.table[data-item-per-page]');
        this.init();
    }

    init() {
        this.tables.forEach(table => this.setupTable(table));
    }

    setupTable(table) {
        const rows = Array.from(table.querySelectorAll('tbody tr'));
        const perPage = parseInt(table.getAttribute('data-item-per-page'), 10) || 5;
        const totalPages = Math.max(1, Math.ceil(rows.length / perPage));
        const pagination = table.parentElement.querySelector('.pagination');

        if (!pagination) {
            rows.forEach((r, i) => {
                r.style.display = i < perPage ? '' : 'none';
            });
            return;
        }

        if (pagination.querySelectorAll('.page').length === 0) {
            const nextBtn = pagination.querySelector('.next-button');
            for (let i = 1; i <= totalPages; i++) {
                const p = document.createElement('div');
                p.className = 'page';
                p.textContent = i;
                pagination.insertBefore(p, nextBtn);
            }
        }

        const sizePagination = pagination.dataset.paginationSize;

        if (sizePagination) {
            pagination.style.setProperty('--pagination-size', sizePagination);
        }

        const pages = Array.from(pagination.querySelectorAll('.page'));
        const prev = pagination.querySelector('.previous-button');
        const next = pagination.querySelector('.next-button');

        const showPage = (pageNumber) => {
            const start = (pageNumber - 1) * perPage;
            const end = start + perPage;

            rows.forEach((r, i) => {
                r.style.display = i >= start && i < end ? '' : 'none';
            });

            paginationInstance.activatePage(pages[pageNumber - 1], pages);
        };

        pages.forEach((p, i) => {
            p.addEventListener('click', () => showPage(i + 1));
        });

        prev?.addEventListener('click', () => {
            const activeIndex = pages.findIndex(p => p.classList.contains('active'));
            if (activeIndex > 0) showPage(activeIndex);
        });

        next?.addEventListener('click', () => {
            const activeIndex = pages.findIndex(p => p.classList.contains('active'));
            if (activeIndex < pages.length - 1) showPage(activeIndex + 2);
        });

        showPage(1);
    }
}

new TablePaginator();

